import { HeroSection } from '@/components/sections/HeroSection'
import { FeatureSection } from '@/components/sections/FeatureSection'

export default function Page() {
  return (
    <main>
      <HeroSection />
      <FeatureSection />
    </main>
  )
}

import { CTAGroup } from '@/components/ui/CTAGroup'

export function HeroSection() {
  return (
    <section className="w-full flex flex-col items-center justify-center gap-8 px-20 py-[120px] bg-[#0F0F11]">
      {/* Badge */}
      <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-indigo-500/15">
        <span className="text-[13px] font-medium text-indigo-400">AI-Powered</span>
      </div>

      {/* Heading */}
      <h1 className="text-6xl font-extrabold leading-tight tracking-tighter text-zinc-100 text-center">
        Design to Code,<br />
        Powered by AI
      </h1>

      {/* Subtitle */}
      <p className="text-lg font-normal leading-7 text-zinc-400 text-center max-w-2xl">
        Analyze Figma designs and generate production-ready React + Tailwind code with AI interpretation.
      </p>

      {/* CTA Buttons */}
      <CTAGroup />
    </section>
  )
}

import { FeatureCard } from '@/components/cards/FeatureCard'

const features = [
  {
    id: 'token-extraction',
    title: 'Token Extraction',
    description: 'Automatically extracts colors, typography, spacing, and border radius from your Figma frames.',
  },
  {
    id: 'ai-interpretation',
    title: 'AI Interpretation',
    description: 'Claude AI analyzes the component hierarchy and suggests meaningful component names and structure.',
  },
  {
    id: 'code-generation',
    title: 'Code Generation',
    description: 'Generates production-ready React + Tailwind code with proper component separation and TypeScript types.',
  },
]

export function FeatureSection() {
  return (
    <section className="w-full flex flex-col items-center gap-16 px-20 py-24 bg-[#1A1A1F]">
      {/* Section Header */}
      <div className="flex flex-col items-center gap-4">
        <h2 className="text-4xl font-bold leading-tight text-zinc-100 text-center">
          Everything you need
        </h2>
        <p className="text-base font-normal leading-6 text-zinc-400 text-center">
          From design to production code in minutes
        </p>
      </div>

      {/* Feature Grid */}
      <div className="grid grid-cols-3 gap-6 w-full max-w-5xl">
        {features.map((feature) => (
          <FeatureCard
            key={feature.id}
            title={feature.title}
            description={feature.description}
          />
        ))}
      </div>
    </section>
  )
}

interface FeatureCardProps {
  title: string
  description: string
}

export function FeatureCard({ title, description }: FeatureCardProps) {
  return (
    <div className="flex flex-col gap-4 p-6 rounded-xl bg-[#222228] border border-[#2A2A35]">
      {/* Icon Container */}
      <div className="w-10 h-10 rounded-lg bg-indigo-500/15 flex items-center justify-center">
        {/* SVG 아이콘 직접 삽입 필요 */}
        <div className="w-5 h-5 bg-indigo-400/50 rounded" />
      </div>

      {/* Title */}
      <h3 className="text-lg font-semibold text-zinc-100">
        {title}
      </h3>

      {/* Description */}
      <p className="text-sm font-normal leading-relaxed text-zinc-400">
        {description}
      </p>
    </div>
  )
}
